import{_ as a,o,c as t,a3 as i}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Web.Core","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/web-core.md","filePath":"cosmos/framework/packages/web-core.md","lastUpdated":1783216089000}'),r={name:"cosmos/framework/packages/web-core.md"};function s(n,e,d,l,c,h){return o(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="xihan-framework-web-core" tabindex="-1">XiHan.Framework.Web.Core <a class="header-anchor" href="#xihan-framework-web-core" aria-label="Permalink to &quot;XiHan.Framework.Web.Core&quot;">​</a></h1><blockquote><p>Web 基础设施：托管环境抽象、HttpContext 支持、客户端信息识别（IP 地理定位与 UA 解析）与当前主体访问。</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Web.Core</code></li><li><strong>模块类</strong>：<code>XiHanWebCoreModule</code></li><li><strong>所在层</strong>：Web 层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>XiHan.Framework.Web.Core 是所有 Web 相关包的公共底座。它把「当前请求」这件事在框架里落地：注册 <code>IHttpContextAccessor</code>，把 ASP.NET Core 的托管环境接入框架的 <code>IXiHanHostEnvironment</code>，用 <code>HttpContext.User</code> 作为框架 <code>ICurrentUser</code>/<code>ICurrentPrincipalAccessor</code> 的数据源，并提供一个「客户端信息识别」服务——从请求里解析出真实 IP、地理位置、浏览器/操作系统/设备。</p><p>其它 Web 包（Web.Api、Web.Docs、Web.Grpc、Web.RealTime、Web.Gateway）都依赖它。你自己一般不直接引用，而是通过上层包间接获得它。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要在服务里拿到「当前登录用户」——本包让框架的 <code>ICurrentUser</code> 在 Web 请求中可用。</li><li>需要识别请求来源：真实客户端 IP（穿透 <code>X-Forwarded-For</code>/<code>X-Real-IP</code>）、归属地、浏览器与设备（登录日志、审计、风控常用）。</li><li>需要一个统一的 <code>IApplicationBuilder</code>/托管环境访问入口，供模块化生命周期使用。</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Web.Core</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanWebCoreModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 中调用 <code>AddXiHanWebCore(config)</code>，注册 <code>IHttpContextAccessor</code>、客户端信息提供器与当前主体访问器。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>托管环境接入</strong>：把 ASP.NET Core 的 <code>IWebHostEnvironment</code> 环境名同步到框架的 <code>IXiHanHostEnvironment</code>。</li><li><strong>HttpContext 与当前主体</strong>：注册 <code>IHttpContextAccessor</code>；用 <code>HttpContextCurrentPrincipalAccessor</code> 让框架 <code>ICurrentUser</code> 读取 <code>HttpContext.User</code>。</li><li><strong>客户端信息识别</strong>：<code>IClientInfoProvider</code> 从当前请求解析 <code>ClientInfo</code>（IP、地理位置、浏览器、操作系统、设备）。</li><li><strong>真实 IP 解析</strong>：优先取 <code>X-Forwarded-For</code> 第一跳，其次 <code>X-Real-IP</code>，回退连接远端地址；识别回环（本机）与内网（局域网）。</li><li><strong>IP 地理定位</strong>：基于 <code>ip2region</code>（<code>IP2Region.Net</code>）离线库解析归属地，仅公网 IP 触发；数据库文件按候选路径自动探测，缺库时静默跳过。</li><li><strong>UA 解析</strong>：基于 <code>UAParser</code> 解析 User-Agent，得到浏览器/系统/设备名。</li><li><strong>Claims 转换</strong>：可选的 <code>XiHanClaimsTransformation</code>（通过 <code>TransformXiHanClaims()</code> 注册），支持声明映射。</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>IClientInfoProvider</code> / <code>ClientInfo</code></td><td>客户端信息提供器接口与结果模型（IP/位置/浏览器/系统/设备）</td></tr><tr><td><code>HttpContextClientInfoProvider</code></td><td>默认实现：真实 IP 解析 + ip2region 地理定位 + UAParser 解析</td></tr><tr><td><code>XiHanClientInfoOptions</code></td><td>客户端信息配置（是否启用 IP 归属地、ip2region 库路径等）</td></tr><tr><td><code>HttpContextCurrentPrincipalAccessor</code></td><td>以 <code>HttpContext.User</code> 作为当前主体，桥接框架 <code>ICurrentUser</code></td></tr><tr><td><code>XiHanClaimsTransformation</code> / <code>XiHanClaimsMapOptions</code></td><td>身份声明转换与声明映射选项</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li>内部依赖：<a href="./core">XiHan.Framework.Core</a>、<a href="./authentication">XiHan.Framework.Authentication</a>、<a href="./security">XiHan.Framework.Security</a>。</li><li>第三方核心：<code>IP2Region.Net</code>（离线 IP 归属地）与 <code>UAParser</code>（User-Agent 解析）。</li><li>该包 SDK 为 <code>Microsoft.NET.Sdk.Web</code>，可直接使用 ASP.NET Core 类型。</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./web-api">XiHan.Framework.Web.Api</a> — 在其之上装配完整的 REST API 中间件管道。</li><li><a href="./web-realtime">XiHan.Framework.Web.RealTime</a>、<a href="./web-grpc">XiHan.Framework.Web.Grpc</a>、<a href="./web-gateway">XiHan.Framework.Web.Gateway</a> — 其它 Web 层包，均以本包为底座。</li></ul>`,21)])])}const b=a(r,[["render",s]]);export{k as __pageData,b as default};
